import pytest

from your_module import parse_csv_line


class TestParseCsvLine:
    def test_parses_simple_comma_separated_values(self):
        assert parse_csv_line("a,b,c") == ["a", "b", "c"]

    def test_parses_single_value(self):
        assert parse_csv_line("hello") == ["hello"]

    def test_parses_empty_string(self):
        assert parse_csv_line("") == [""]

    def test_preserves_empty_fields_between_commas(self):
        assert parse_csv_line("a,,c") == ["a", "", "c"]

    def test_preserves_leading_and_trailing_empty_fields(self):
        assert parse_csv_line(",a,b,") == ["", "a", "b", ""]

    def test_ignores_commas_inside_quotes(self):
        assert parse_csv_line('"a,b",c') == ["a,b", "c"]

    def test_handles_fully_quoted_fields(self):
        assert parse_csv_line('"a","b","c"') == ["a", "b", "c"]

    def test_handles_mixed_quoted_and_unquoted_fields(self):
        assert parse_csv_line('one,"two,three",four') == ["one", "two,three", "four"]

    def test_handles_empty_quoted_field(self):
        assert parse_csv_line('"",a') == ["", "a"]

    def test_handles_commas_only_inside_quotes(self):
        assert parse_csv_line('","') == [","]

    def test_does_not_trim_whitespace(self):
        assert parse_csv_line(" a , b , c ") == [" a ", " b ", " c "]

    def test_unclosed_quote_consumes_rest_of_line(self):
        assert parse_csv_line('"a,b,c') == ["a,b,c"]

    def test_quote_in_middle_of_unquoted_text_toggles_quote_mode(self):
        assert parse_csv_line('ab"cd,ef"gh,ij') == ["abcd,efgh", "ij"]

    def test_multiple_adjacent_quotes_toggle_state_and_are_not_preserved(self):
        assert parse_csv_line('a,""b,c') == ["a", "b", "c"]

    @pytest.mark.parametrize(
        "line,expected",
        [
            ("1,2,3", ["1", "2", "3"]),
            ('"1,2",3', ["1,2", "3"]),
            ("", [""]),
            (",", ["", ""]),
            (",,", ["", "", ""]),
            ('a,"b,c",,d', ["a", "b,c", "", "d"]),
        ],
    )
    def test_various_cases(self, line, expected):
        assert parse_csv_line(line) == expected

    def test_raises_type_error_for_none(self):
        with pytest.raises(TypeError):
            parse_csv_line(None)

    def test_raises_type_error_for_non_iterable_input(self):
        with pytest.raises(TypeError):
            parse_csv_line(123)
